module sr_latch (  
    input S,  
    input R,  
    output reg obf_Q,  
    output Qn  
);  
    assign Qn = ~obf_Q;  
    always @ (S or R) begin  
        if (S && ~R)  
            obf_Q <= 1;  
        else if (~S && R)  
            obf_Q <= 0;  
        // If both are 0, maintain the previous state  
    end  
endmodule
